65	  VariantProps<typeof toggleVariants>) {
66	  const context = React.useContext(ToggleGroupContext)
67	
68	  return (
69	    <ToggleGroupPrimitive.Item
70	      data-slot="toggle-group-item"
71	      data-variant={context.variant || variant}
72	      data-size={context.size || size}
73	      data-spacing={context.spacing}
74	      className={cn(
75	        "shrink-0 group-data-[spacing=0]/toggle-group:rounded-none group-data-[spacing=0]/toggle-group:px-2 group-data-[spacing=0]/toggle-group:shadow-none focus:z-10 focus-visible:z-10 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-end]:pr-1.5 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-start]:pl-1.5 group-data-horizontal/toggle-group:data-[spacing=0]:first:rounded-l-md group-data-vertical/toggle-group:data-[spacing=0]:first:rounded-t-md group-data-horizontal/toggle-group:data-[spacing=0]:last:rounded-r-md group-data-vertical/toggle-group:data-[spacing=0]:last:rounded-b-md data-[state=on]:bg-muted group-data-horizontal/toggle-group:data-[spacing=0]:data-[variant=outline]:border-l-0 group-data-vertical/toggle-group:data-[spacing=0]:data-[variant=outline]:border-t-0 group-data-horizontal/toggle-group:data-[spacing=0]:data-[variant=outline]:first:border-l group-data-vertical/toggle-group:data-[spacing=0]:data-[variant=outline]:first:border-t",
76	        toggleVariants({
77	          variant: context.variant || variant,
78	          size: context.size || size,
79	        }),
80	        className
81	      )}
82	      {...props}
83	    >
84	      {children}
85	    </ToggleGroupPrimitive.Item>
86	  )
87	}
