content.text:
Excellent! Now I have a comprehensive view of the registry and example patterns. Let me compile my findings into a detailed report.

## Registry Pattern Analysis Report

Based on my thorough reading of the shadcn/ui v4 codebase, here are the exact patterns and structure you need to follow:

### 1. UI Component Registry Pattern (`apps/v4/registry/new-york-v4/ui/_registry.ts`)

**File Structure:**
```typescript
import { type Registry } from "shadcn/schema"

export const ui: Registry["items"] = [
  // Registry entries array
]
```

**Registry Entry Structure:**

**Basic UI Component (No Dependencies):**
```typescript
{
  name: "card",
  type: "registry:ui",
  files: [
    {
      path: "ui/card.tsx",
      type: "registry:ui",
    },
  ],
}
```

**Component with NPM Dependencies:**
```typescript
{
  name: "accordion",
  type: "registry:ui",
  dependencies: ["radix-ui"],
  files: [
    {
      path: "ui/accordion.tsx",
      type: "registry:ui",
    },
  ],
}
```

**Component with Multiple Files (Hooks, Related Components):**
```typescript
{
  name: "toast",
  type: "registry:ui",
  dependencies: ["radix-ui"],
  files: [
    {
      path: "ui/toast.tsx",
      type: "registry:ui",
    },
    {
      path: "hooks/use-toast.ts",
      type: "registry:hook",
    },
    {
      path: "ui/toaster.tsx",
      type: "registry:ui",
    },
  ],
}
```

**Component with Registry Dependencies (depends on other UI components):**
```typescript
{
  name: "alert-dialog",
  type: "registry:ui",
  dependencies: ["radix-ui"],
  registryDependencies: ["button"],
  files: [
    {
      path: "ui/alert-dialog.tsx",
      type: "registry:ui",
    },
  ],
}
```

**Complex Component with Tailwind Config and CSS Variables:**
```typescript
{
  name: "sidebar",
  type: "registry:ui",
  dependencies: ["radix-ui", "class-variance-authority", "lucide-react"],
  registryDependencies: [
    "button",
    "separator",
    "sheet",
    "tooltip",
    "input",
    "use-mobile",
    "skeleton",
  ],
  files: [
    {
      path: "ui/sidebar.tsx",
      type: "registry:ui",
    },
  ],
  tailwind: {
    config: {
      theme: {
        extend: {
          colors: {
            sidebar: {
              DEFAULT: "hsl(var(--sidebar-background))",
              // ... more color definitions
            },
          },
        },
      },
    },
  },
  cssVars: {
    light: {
      "sidebar-background": "0 0% 98%",
      // ... more variables
    },
    dark: {
      "sidebar-background": "240 5.9% 10%",
      // ... more variables
    },
  },
}
```

**Registry Entry Fields:**
- `name` (string): Unique identifier for the component (kebab-case)
- `type` (string): Always `"registry:ui"` for UI components
- `dependencies` (string[], optional): NPM packages required (e.g., `["radix-ui"]`)
- `registryDependencies` (string[], optional): Other registry components this depends on
- `files` (object[], required): Array of file objects with `path` and `type`
- `docs` (string, optional): Markdown documentation shown after installation
- `tailwind` (object, optional): Tailwind config overrides/extensions
- `cssVars` (object, optional): CSS custom variables for light/dark themes

---

### 2. Examples Registry Pattern (`apps/v4/registry/new-york-v4/examples/_registry.ts`)

**File Structure:**
```typescript
import { type Registry } from "shadcn/schema"

export const examples: Registry["items"] = [
  // Registry entries array
]
```

**Basic Example Entry:**
```typescript
{
  name: "accordion-demo",
  type: "registry:example",
  registryDependencies: ["accordion"],
  files: [
    {
      path: "examples/accordion-demo.tsx",
      type: "registry:example",
    },
  ],
}
```

**Multiple Variations of Same Component:**
```typescript
{
  name: "badge-demo",
  type: "registry:example",
  registryDependencies: ["badge"],
  files: [
    {
      path: "examples/badge-demo.tsx",
      type: "registry:example",
    },
  ],
},
{
  name: "badge-destructive",
  type: "registry:example",
  registryDependencies: ["badge"],
  files: [
    {
      path: "examples/badge-destructive.tsx",
      type: "registry:example",
    },
  ],
},
{
  name: "badge-outline",
  type: "registry:example",
  registryDependencies: ["badge"],
  files: [
    {
      path: "examples/badge-outline.tsx",
      type: "registry:example",
    },
  ],
},
```

**Example Entry Fields:**
- `name` (string): Unique identifier (kebab-case, e.g., `"accordion-demo"`, `"button-loading"`)
- `type` (string): Always `"registry:example"`
- `registryDependencies` (string[]): UI components this example uses
- `files` (object[]): Single file object with `path` and `type: "registry:example"`

**Naming Conventions:**
- Primary/default example: `{component-name}-demo` (e.g., `accordion-demo`, `carousel-demo`)
- Variant examples: `{component-name}-{variant}` (e.g., `button-loading`, `badge-outline`, `button-with-icon`)

---

### 3. Example Demo File Patterns

**File Location:** `apps/v4/registry/new-york-v4/examples/{name}.tsx`

**Pattern 1: Simple Stateless Component (No Client-Side State)**
```typescript
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from "@/registry/new-york-v4/ui/accordion"

export default function AccordionDemo() {
  return (
    <Accordion type="single" collapsible className="w-full" defaultValue="item-1">
      <AccordionItem value="item-1">
        <AccordionTrigger>Product Information</AccordionTrigger>
        <AccordionContent className="flex flex-col gap-4 text-balance">
          <p>Content here</p>
        </AccordionContent>
      </AccordionItem>
      {/* More items */}
    </Accordion>
  )
}
```

**Pattern 2: Client-Side Stateful Component (with `"use client"` directive)**
```typescript
"use client"

import * as React from "react"
import { Check, ChevronsUpDown } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/registry/new-york-v4/ui/button"
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/registry/new-york-v4/ui/command"
import { Popover, PopoverContent, PopoverTrigger } from "@/registry/new-york-v4/ui/popover"

const frameworks = [
  { value: "next.js", label: "Next.js" },
  { value: "sveltekit", label: "SvelteKit" },
  // ...
]

export default function ComboboxDemo() {
  const [open, setOpen] = React.useState(false)
  const [value, setValue] = React.useState("")

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" role="combobox" aria-expanded={open} className="w-[200px] justify-between">
          {value ? frameworks.find((framework) => framework.value === value)?.label : "Select framework..."}
          <ChevronsUpDown className="opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[200px] p-0">
        <Command>
          <CommandInput placeholder="Search framework..." className="h-9" />
          <CommandList>
            <CommandEmpty>No framework found.</CommandEmpty>
            <CommandGroup>
              {frameworks.map((framework) => (
                <CommandItem
                  key={framework.value}
                  value={framework.value}
                  onSelect={(currentValue) => {
                    setValue(currentValue === value ? "" : currentValue)
                    setOpen(false)
                  }}
                >
                  {framework.label}
                  <Check className={cn("ml-auto", value === framework.value ? "opacity-100" : "opacity-0")} />
                </CommandItem>
              ))}
            </CommandGroup>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}
```

**Pattern 3: Component with Hooks**
```typescript
"use client"

import * as React from "react"
import Link from "next/link"
import { useIsMobile } from "@/registry/new-york-v4/hooks/use-mobile"
