# Stepper Component Implementation Plan

## Context

Add a new "Stepper" compound component to the shadcn/ui v4 component library. Steppers display multi-step progress indicators for wizards, onboarding flows, and checkout processes. This is a new component — no existing files are modified, only new files created and registry entries appended.

## Files to Create / Modify

| Action | File |
|--------|------|
| **Create** | `apps/v4/registry/new-york-v4/ui/stepper.tsx` |
| **Create** | `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` |
| **Edit** | `apps/v4/registry/new-york-v4/ui/_registry.ts` — insert entry after line 563 (after `spinner`, before `switch`) |
| **Edit** | `apps/v4/registry/new-york-v4/examples/_registry.ts` — insert entry after line 2124 (after `spinner-item`, before `switch-demo`) |

## Step 1: Create `stepper.tsx`

**Path:** `apps/v4/registry/new-york-v4/ui/stepper.tsx`

Follow the carousel.tsx context pattern (custom React context, no Radix dependency). Use tabs.tsx `data-orientation` pattern.

### File structure (in order):

```tsx
"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
```

### 1a. Context types and creation

```tsx
type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}
```

Second context for StepperItem to pass step number down to children:

```tsx
type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}
```

### 1b. `Stepper` — root container

```tsx
function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}
```

### 1c. `StepperItem` — wrapper per step

```tsx
function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()
  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}
```

### 1d. `StepperTrigger` — clickable step indicator (circle/number)

```tsx
function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex size-8 items-center justify-center rounded-full border text-sm font-medium transition-colors",
        "focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "bg-primary text-primary-foreground border-primary",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/25 text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}
```

### 1e. `StepperTitle`

```tsx
function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}
```

### 1f. `StepperDescription`

```tsx
function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}
```

### 1g. `StepperSeparator`

Styled as a line between steps. Uses orientation from context. Visual state based on whether the *next* step is completed (i.e., derives from parent StepperItem's step number).

```tsx
function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation, activeStep } = useStepper()
  const { step } = useStepperItem()
  const isCompleted = step < activeStep

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "pending"}
      className={cn(
        "bg-muted-foreground/25 transition-colors data-[state=completed]:bg-primary",
        orientation === "horizontal" ? "h-0.5 flex-1" : "ml-4 w-0.5 min-h-4",
        className
      )}
      {...props}
    />
  )
}
```

### 1h. `StepperContent` — conditional content panel

```tsx
function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}
```

### 1i. Named exports

```tsx
export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

## Step 2: Create `stepper-demo.tsx`

**Path:** `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

A 3-step horizontal stepper with "Account", "Profile", "Complete". Uses `React.useState` for `activeStep`. Includes "Next" / "Previous" buttons.

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { step: 1, title: "Account", description: "Create your account" },
  { step: 2, title: "Profile", description: "Set up your profile" },
  { step: 3, title: "Complete", description: "Review and finish" },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        {steps.map((s, index) => (
          <React.Fragment key={s.step}>
            <StepperItem step={s.step}>
              <StepperTrigger onClick={() => setActiveStep(s.step)} />
              <div>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </div>
            </StepperItem>
            {index < steps.length - 1 && (
              <StepperSeparator /> {/* rendered outside StepperItem — need adjustment */}
            )}
          </React.Fragment>
        ))}
      </Stepper>

      {/* Step content panels */}
      <StepperContent ... />

      {/* Nav buttons */}
      <div className="flex gap-2">
        <Button variant="outline" ... >Previous</Button>
        <Button ... >Next</Button>
      </div>
    </div>
  )
}
```

**Design consideration:** `StepperSeparator` uses `useStepperItem()` context, so it must be placed *inside* a `StepperItem`. The demo should place the separator inside each `StepperItem` (after the trigger/title group). `StepperContent` uses `useStepper()` context, so it must be inside `<Stepper>`. I'll finalize the exact JSX in implementation.

## Step 3: Add UI registry entry

**File:** `apps/v4/registry/new-york-v4/ui/_registry.ts`  
**Insert after line 563** (after the `spinner` entry's closing `},`, before the `switch` entry):

```ts
  {
    name: "stepper",
    type: "registry:ui",
    files: [
      {
        path: "ui/stepper.tsx",
        type: "registry:ui",
      },
    ],
  },
```

No `dependencies` needed — no external packages (no Radix, no cva). No `registryDependencies` — doesn't import other registry components.

## Step 4: Add example registry entry

**File:** `apps/v4/registry/new-york-v4/examples/_registry.ts`  
**Insert after line 2124** (after `spinner-item` entry's closing `},`, before `switch-demo`):

```ts
  {
    name: "stepper-demo",
    type: "registry:example",
    registryDependencies: ["stepper"],
    files: [
      {
        path: "examples/stepper-demo.tsx",
        type: "registry:example",
      },
    ],
  },
```

## Key Patterns to Follow (from exploration)

- **`"use client"`** at top of both files
- **`import * as React from "react"`** — star import style
- **`cn()` from `"@/lib/utils"`** for all className merging; base classes first, `className` prop last
- **`data-slot="stepper-*"`** on every rendered element
- **`data-state`** attribute on stateful elements (`StepperItem`, `StepperTrigger`, `StepperSeparator`)
- **`data-orientation`** on root `Stepper`
- **`React.ComponentProps<"element">`** for props typing (not `ComponentPropsWithoutRef`)
- **Function declarations** (`function Foo() {}`) — never arrow functions
- **Named exports only** — `export { ... }` at bottom
- **Custom context** following carousel.tsx pattern: `createContext<T | null>(null)` + custom hook with error throw
- **Two contexts**: one for stepper-level (activeStep, orientation) and one for item-level (step, state) — mirrors how sidebar.tsx uses nested context

## Verification

1. **TypeScript check:** Run `npx tsc --noEmit` from the `apps/v4` directory to verify no type errors
2. **Visual check:** The stepper-demo should render in the component preview system
3. **Registry check:** Verify `stepper` appears in the registry output by searching `_registry.ts` for the entry
4. **Functionality check:** Clicking Next/Previous in the demo should advance/retreat the active step, updating visual states of triggers and separators

